arguments.command:
$ErrorActionPreference='Stop'
$token=$env:GHL_PRIVATE_INTEGRATION_TOKEN
if(-not $token){ throw 'Missing GHL token' }
$headers=@{Authorization="Bearer $token"; Version='2021-07-28'; Accept='application/json'}
$loc='TW8JsPW5NMnA3tfK2XLn'
$since=(Get-Date).ToUniversalTime().AddHours(-24)

$convUrl="https://services.leadconnectorhq.com/conversations/search?locationId=$loc&limit=100"
$convs=(Invoke-RestMethod -Method GET -Uri $convUrl -Headers $headers).conversations
if(-not $convs){ $convs=@() }

$all=@()
foreach($c in $convs){
  $cid=$c.id
  $url="https://services.leadconnectorhq.com/conversations/$cid/messages?limit=200"
  try{
    $resp=Invoke-RestMethod -Method GET -Uri $url -Headers $headers
    $msgs=$resp.messages.messages
    if($msgs){ $all += $msgs }
  } catch {}
}

$recent=$all | Where-Object { [datetime]$_.dateAdded -ge $since }
$outbound=$recent | Where-Object { $_.direction -eq 'outbound' }
$inbound=$recent | Where-Object { $_.direction -eq 'inbound' }
$totalOut=[double]($outbound.Count)
if($totalOut -eq 0){ $totalOut=1 }

$optWords='stop|unsubscribe|opt\s*out|quit|cancel|remove me|do not contact|don\'t text|dont text|no more'
$complaintWords='spam|report|complaint|harass|abuse|scam|lawsuit|attorney|legal action|fcc|ftc'
$optCount=($inbound | Where-Object { ($_.body -as [string]) -match $optWords }).Count
$complaintCount=($inbound | Where-Object { ($_.body -as [string]) -match $complaintWords }).Count

$hardFailStatuses=@('failed','undelivered','error','delivery_failed','bounced','rejected','invalid')
$hardFailCount=($outbound | Where-Object { $hardFailStatuses -contains (($_.status -as [string]).ToLower()) }).Count

# duplicate heuristic: same conversationId + same body + within 10 minutes
$dupCount=0
$grp=$outbound | Group-Object conversationId
foreach($g in $grp){
  $msgs=$g.Group | Sort-Object {[datetime]$_.dateAdded}
  for($i=1;$i -lt $msgs.Count;$i++){
    $a=$msgs[$i-1]; $b=$msgs[$i]
    if(($a.body -as [string]) -eq ($b.body -as [string])){
      $dt=([datetime]$b.dateAdded - [datetime]$a.dateAdded).TotalMinutes
      if($dt -le 10){ $dupCount++ }
    }
  }
}

$optRate= [math]::Round(($optCount/$totalOut)*100,3)
$complaintRate=[math]::Round(($complaintCount/$totalOut)*100,3)
$dupRate=[math]::Round(($dupCount/$totalOut)*100,3)
$hardFailRate=[math]::Round(($hardFailCount/$totalOut)*100,3)

[pscustomobject]@{
  outboundCount=[int]($outbound.Count)
  inboundCount=[int]($inbound.Count)
  optOutCount=[int]$optCount
  complaintCount=[int]$complaintCount
  duplicateCount=[int]$dupCount
  hardFailCount=[int]$hardFailCount
  optOutRate=$optRate
  complaintRate=$complaintRate
  duplicateRate=$dupRate
  hardFailRate=$hardFailRate
} | ConvertTo-Json -Compress

